<div class="d-flex flex-wrap justify-content-between align-items-center gap-3 mb-4"><div><h1 class="h3 mb-1">Dispatch Board</h1><p class="text-muted mb-0">Assign jobs to crews or individual technicians. Crew defaults fill the leader and vehicle automatically.</p></div><form class="d-flex gap-2"><input type="date" class="form-control" name="date" value="<?=e($date)?>"><select class="form-select" name="crew_id"><option value="">All crews</option><?php foreach($crews as $c):?><option value="<?=$c['id']?>" <?=selected($crewFilter,$c['id'])?>><?=e($c['name'])?></option><?php endforeach?></select><button class="btn btn-primary">Load</button></form></div>
<div class="alert alert-info"><i class="fa-solid fa-circle-info me-2"></i>Moving a job into a crew column records assignment history and uses the crew's default leader and vehicle unless overridden.</div>
<div class="dispatch-board" data-date="<?=e($date)?>" data-csrf="<?=e(csrf_token())?>"><div class="dispatch-column"><div class="dispatch-column-header">Unassigned</div><div class="dispatch-dropzone" data-crew="" data-tech=""><?php foreach($jobs as $j)if(!$j['crew_id']&&!$j['assigned_user_id']):?><?php include __DIR__.'/job-card.php';?><?php endif?></div></div><?php foreach($crews as $crew):?><div class="dispatch-column"><div class="dispatch-column-header"><span><?=e($crew['name'])?></span><small class="d-block opacity-75"><?=e($crew['leader_name']?:'No leader')?> · <?=e($crew['vehicle_unit']?:'No vehicle')?></small></div><div class="dispatch-dropzone" data-crew="<?=$crew['id']?>" data-tech="<?=$crew['crew_leader_id']?>"><?php foreach($jobs as $j)if((int)$j['crew_id']===(int)$crew['id']):?><?php include __DIR__.'/job-card.php';?><?php endif?></div></div><?php endforeach?></div>
<script>(()=>{let dragged=null;document.querySelectorAll('.dispatch-card').forEach(c=>c.addEventListener('dragstart',()=>{dragged=c;c.classList.add('dragging')}));document.querySelectorAll('.dispatch-card').forEach(c=>c.addEventListener('dragend',()=>c.classList.remove('dragging')));document.querySelectorAll('.dispatch-dropzone').forEach(z=>{z.addEventListener('dragover',e=>{e.preventDefault();z.classList.add('drag-over')});z.addEventListener('dragleave',()=>z.classList.remove('drag-over'));z.addEventListener('drop',async e=>{e.preventDefault();z.classList.remove('drag-over');if(!dragged)return;z.appendChild(dragged);await saveBoard();});});document.addEventListener('change',e=>{if(e.target.matches('.vehicle-select,.tech-select'))saveBoard();});async function saveBoard(){const board=document.querySelector('.dispatch-board');let requests=[];document.querySelectorAll('.dispatch-dropzone').forEach(zone=>{[...zone.querySelectorAll('.dispatch-card')].forEach((card,index)=>{let form=new FormData();form.append('_csrf',board.dataset.csrf);form.append('job_id',card.dataset.job);form.append('crew_id',zone.dataset.crew||'');form.append('assigned_user_id',card.querySelector('.tech-select')?.value||zone.dataset.tech||'');form.append('assigned_vehicle_id',card.querySelector('.vehicle-select')?.value||'');form.append('route_date',board.dataset.date);form.append('route_order',index+1);form.append('assignment_source','dispatch');requests.push(fetch('/portal/dispatch/update',{method:'POST',body:form,headers:{'Accept':'application/json'}}));});});await Promise.all(requests);}})();</script>
